def perceive(data):
    text = data if isinstance(data, str) else str(data)
    out = {}
    for line in text.splitlines():
        if ":" not in line:
            continue
        key, val = line.split(":", 1)
        key = key.strip().lower()
        val = val.strip()
        if key in ("amount", "offer"):
            try:
                out["current_offer"] = round(float(val.replace(",", "").lstrip("$")), 2)
            except ValueError:
                pass
        elif key in ("party", "from", "offer_by"):
            out["offer_by"] = val
    return out
